import React, { useState } from 'react'

const page = () => {

    const [formData, setFormData] = useState({
      offer_letter: null,
      admission_letter: null,
      bonafide_certificate: null,
      student_undertaking_form: null,
    });

    const handleFileChange = (e) => {
      const file = e.target.files[0];
      if (file) {
        setFormData({ ...formData, [e.target.name]: file });

      }
    };

      const handleSubmit = async (e) => {
        e.preventDefault();
        if (!formData.id) {
          toast.error("User ID is missing!");
          return;
        }

        setLoading(true);
        const formDataToSend = new FormData();
        Object.keys(formData).forEach((key) => {
          if (formData[key]) {
            formDataToSend.append(key, formData[key]);
          }
        });

        try {
          toast.loading("Updating profile...");
          const res = await fetch("/api/update-profile", {
            method: "POST",
            body: formDataToSend,
          });

          const email = JSON.parse(localStorage.getItem("user")).email;

          axios.post("/api/getuserbyemail", { email }).then((res) => {
            console.log(res.data);

            localStorage.setItem("user", JSON.stringify(res.data.user));
          });

          const data = await res.json();
          toast.dismiss();
          setLoading(false);

          if (res.ok) {
            toast.success("Profile updated successfully!");
            localStorage.setItem("document_verified", "0");

            axios
              .post("/api/documentverify/iseligible/updatetozero", { email })
              .then((res) => {
                console.log(res);
              })
              .catch((err) => {
                console.log(err);
              });
            axios
              .post("/api/documentverify/updatetozero", { email })
              .then((res) => {
                console.log(res);
              })
              .catch((err) => {
                console.log(err);
              });
          } else {
            toast.error(data.error || "Something went wrong");
          }
        } catch (error) {
          setLoading(false);
          toast.dismiss();
          toast.error("Failed to update profile");
        }
      };

  return (
    <div>
      checklist
    </div>
  )
}

export default page
